BEGIN;

-- greenhouse/airbnb: Acquisition Manager
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('ce296f1c-bd1b-4edb-8844-c27a5d0cf236', 'greenhouse', '7995199', 'airbnb', 'Acquisition Manager', 'Paris, France', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Community You Will Join:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;The Homes team plays a key role in shaping the Airbnb stays experience. As a multidisciplinary team, we partner with Hosts to conceptualize and develop high-quality, repeatable, and commercially viable offerings that align with our brand values.&lt;/p&gt;
&lt;p&gt;Airbnb is seeking a Market Manager, with a primary focus on France, to support and grow our network of Hosts and Partners. This role will be part of the Homes EMEA team and report to the Field Operations Manager.&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Difference You will Make:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;As an Acquisition Manager, you will be responsible for supply acquisition and onboarding of high quality inventory. You will build Airbnb&#39;s strong market presence in France and collaborate with other teams as the local in-market expert. As someone who knows the Airbnb mission and values inside out, you will drive all phases of supply acquisition and market success from acquisition strategy development to strategic partner relationship management. You will help develop and iterate scalable, localized supply acquisition strategies in your territory aiming to secure our long-term success.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;A typical day:&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Prospect and onboard new, high quality hosts in your assigned territory, continuously building and managing a strong pipeline&lt;/li&gt;
&lt;li&gt;Create and deploy scaled strategies to effectively acquire Professional Hosts in your region&lt;/li&gt;
&lt;li&gt;Represent Airbnb in external meetings with Professional Hosts, showing up as a credible and knowledgeable market expert&lt;/li&gt;
&lt;li&gt;Analyze data and utilize data-driven recommendations to identify and act on strategic opportunities in your region to drive sales growth&lt;/li&gt;
&lt;li&gt;Develop deep knowledge of your assigned geographic markets&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Build and manage partner relationships within your assigned territory&lt;/li&gt;
&lt;li&gt;Maintain a baseline understanding of the technical integration of various software partners so that you can provide the right support to your clients&lt;/li&gt;
&lt;li&gt;Educate clients on all significant product changes and cascade feedback on product and policy to relevant internal stakeholders&lt;/li&gt;
&lt;li&gt;Respond to and deliver exceptional service to your hosts in a timely and efficient manner&lt;/li&gt;
&lt;li&gt;Work cross-functionally with product, communications, public policy and customer support teams to ensure our long-term market success&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;6+ years of experience in sales&lt;/li&gt;
&lt;li&gt;2+ years of hospitality/travel industry experience (nice to have)&lt;/li&gt;
&lt;li&gt;Strong time management and prioritization skills&lt;/li&gt;
&lt;li&gt;Strong B2B sales/new business development experience&lt;/li&gt;
&lt;li&gt;Ability to work at both strategic and tactical levels, with a proven track record to execute in ambiguous environments&lt;/li&gt;
&lt;li&gt;Excellent communication skills and ability to communicate effectively with clients&lt;/li&gt;
&lt;li&gt;Experience building and strengthening relationships with external partners&lt;/li&gt;
&lt;li&gt;Comfortable performing data analysis and making decisions based on the results&lt;/li&gt;
&lt;li&gt;Available to travel to assigned markets&lt;/li&gt;
&lt;li&gt;Ability to work within tight deadlines, adjust to changes in priorities, and balance short-term needs with long-term strategic initiatives&lt;/li&gt;
&lt;li&gt;Hospitality/travel industry experience in the region is a plus&lt;/li&gt;
&lt;li&gt;Highly proficient in using CRM software - Salesforce experience is a plus&lt;/li&gt;
&lt;li&gt;Charismatic self-starter who is resourceful and self-sufficient&lt;/li&gt;
&lt;li&gt;Fluency in French and English&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;&lt;div class=&quot;content-pay-transparency&quot;&gt;&lt;div class=&quot;pay-input&quot;&gt;&lt;div class=&quot;description&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0);&quot;&gt;How We&#39;ll Take Care of You:&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;Our job titles may span more than one career level. The actual base pay is dependent upon many factors, such as: training, transferable skills, work experience, business needs and market demands. The base pay range shown below is annualized, is subject to change and may be modified in the future. This role may also be eligible for bonus, equity, benefits, and Employee Travel Credits.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;div class=&quot;title&quot;&gt;France Annual Pay Range&lt;/div&gt;&lt;div class=&quot;pay-range&quot;&gt;&lt;span&gt;€61.000&lt;/span&gt;&lt;span class=&quot;divider&quot;&gt;&amp;mdash;&lt;/span&gt;&lt;span&gt;€72.000 EUR&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', 'https://careers.airbnb.com/positions/7995199?gh_jid=7995199', 'active', now())
