-- greenhouse/airbnb: AMER Gathering Programs Manager
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('15119e1c-9f2b-4327-8c22-02dcf2fef04b', 'greenhouse', '8067991', 'airbnb', 'AMER Gathering Programs Manager', 'New York, United States, Los Angeles, United States', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Community You Will Join:&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;The Gathering Programs Manager is responsible for end-to-end delivery and adaptation of regional Gathering &amp;amp; Culture programs, ensuring they support business priorities and drive meaningful connection across markets.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Difference You Will Make:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;This role translates global strategy into regional execution—owning programs and driving consistency and impact across locations. The individual is a strong program manager who can handle complexity, operate with autonomy, and influence stakeholders.&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;A Typical Day:&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Core Program Ownership&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Own delivery of Host Check-In (2-day program) across EMEA, APAC, and/or AMER, ensuring consistency, quality, and continuous improvement.&lt;/li&gt;
&lt;li&gt;Lead New Hire Connection programs in-region, adapting central strategy to market needs and ensuring high-quality delivery.&lt;/li&gt;
&lt;li&gt;Own New Hire Connection for Global Ops (Dublin, Montreal and India), coordinating cross-functional stakeholders and ensuring alignment with business needs.&lt;/li&gt;
&lt;li&gt;Drive execution of Tech moments (Hackathons, Tech Days, AI Excellence Days) for key tech audiences (Seattle, NYC, Bengaluru, Beijing), ensuring relevance and strong participant experience.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;Regional Adaptation &amp;amp; Program Management&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Adapt global Gathering &amp;amp; Culture strategy to local market context.&lt;/li&gt;
&lt;li&gt;Manage end-to-end delivery of programs across multiple markets.&lt;/li&gt;
&lt;li&gt;Ensure consistency of experience while allowing for cultural nuance.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;Tier 1 Event Ownership&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Act as primary owner for Tier 1 events in-region:&lt;/li&gt;
&lt;ul&gt;
&lt;li&gt;Lead co-design with stakeholders&lt;/li&gt;
&lt;li&gt;Drive pre-production and execution&lt;/li&gt;
&lt;li&gt;Ensure events are tailored to local team needs and business priorities&lt;/li&gt;
&lt;li&gt;Identify risks and ensure high-quality delivery.&lt;/li&gt;
&lt;li&gt;Support planning and delivery of large and strategic offsites, managing key workstreams and ensuring alignment with objectives.&lt;/li&gt;
&lt;/ul&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;Regional Partnership &amp;amp; Strategy Input&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Partner closely with Talent, OD&amp;amp;D, Communications, and business leaders.&lt;/li&gt;
&lt;li&gt;Partner with leaders to identify and design local gathering strategies and connection touchpoints that support priority markets.&lt;/li&gt;
&lt;li&gt;Contribute insights from the region to improve global programs (Releases, Year End Celebration..).&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;Executive Engagement &amp;amp; Visits&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Partner with global and local stakeholders to design and deliver E-team/VP visits.&lt;/li&gt;
&lt;li&gt;Ensure experiences are intentional, locally relevant, and aligned with business goals.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;Budget &amp;amp; Operations&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Manage budgets for assigned programs and events.&lt;/li&gt;
&lt;li&gt;Track performance metrics and program outcomes.&lt;/li&gt;
&lt;li&gt;Identify opportunities to improve efficiency, impact, and scalability&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;6–9+ years in program management, events, or employee experience&lt;/li&gt;
&lt;li&gt;Strong program ownership and execution skills&lt;/li&gt;
&lt;li&gt;Experience working across markets&amp;nbsp; and managing complexity&lt;/li&gt;
&lt;li&gt;Solid stakeholder management and influencing skills&lt;/li&gt;
&lt;li&gt;Ability to operate with autonomy and adapt to ambiguity&lt;/li&gt;
&lt;li&gt;Strong organizational skills and attention to detail&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;color: #000000; font-family: arial, helvetica, sans-serif;&quot;&gt;&lt;strong&gt;Your Location:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;color: #000000; font-family: arial, helvetica, sans-serif;&quot;&gt;Due to the nature of this position, the successful applicant will need to be based in New York City or Los Angeles to be able to conduct their work&amp;nbsp;with flexibility for occasional evenings or weekends in support of events and gatherings. Currently, employees can not be located in: Alaska, Indiana, Nebraska, North Dakota, Ohio, South Dakota, Wisconsin, Alabama, Mississippi, Oklahoma, Delaware And Rhode Island. This list is continuously being updated, please check back with us if the state you live in is on the exclusion list. &amp;nbsp;If your position is employed by another Airbnb entity, your recruiter will inform you what states you are eligible to work from.&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-weight: 400; font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: &lt;/span&gt;&lt;a style=&quot;color: #000000;&quot; href=&quot;mailto:reasonableaccommodations@airbnb.com&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;reasonableaccommodations@airbnb.com&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process.&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-weight: 400; font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application.&lt;/span&gt;&lt;/p&gt;&lt;div class=&quot;content-pay-transparency&quot;&gt;&lt;div class=&quot;pay-input&quot;&gt;&lt;div class=&quot;description&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0);&quot;&gt;How We&#39;ll Take Care of You:&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p class=&quot;p1&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;Our job titles may span more than one career level. The actual base pay is dependent upon many factors, such as: training, transferable skills, work experience, business needs and market demands. The base pay range is subject to change and may be modified in the future. This role may also be eligible for bonus, equity, benefits, and Employee Travel Credits. &amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;div class=&quot;title&quot;&gt;Pay Range&lt;/div&gt;&lt;div class=&quot;pay-range&quot;&gt;&lt;span&gt;$132,000&lt;/span&gt;&lt;span class=&quot;divider&quot;&gt;&amp;mdash;&lt;/span&gt;&lt;span&gt;$154,000 USD&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', 'https://careers.airbnb.com/positions/8067991?gh_jid=8067991', 'active', now())
ON CONFLICT (source, external_id) DO UPDATE SET
  title = EXCLUDED.title,
  location = EXCLUDED.location,
  employment_type = EXCLUDED.employment_type,
  remote = EXCLUDED.remote,
  raw_description = EXCLUDED.raw_description,
  source_url = EXCLUDED.source_url,
  status = 'active',
  last_seen_at = now(),
  updated_at = now()
RETURNING id;

