-- greenhouse/airbnb: Associate Legal Counsel, Japan
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('cdeb961b-a7ed-493e-810e-840f0e34398b', 'greenhouse', '7789554', 'airbnb', 'Associate Legal Counsel, Japan', 'Tokyo, Japan', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Community You Will Join:&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb’s Legal team embodies the company’s innovative, forward-thinking spirit. At the frontier of the sharing economy, Airbnb is breaking new ground in matters of policy, law, and government relations. Where some see obstacles, we see the opportunity to find creative, practical solutions, right at the cutting edge. Our adventurous, fast-moving legal team is committed to building a team of talented, collaborative and self-motivated legal professionals across the globe who believe in Airbnb’s mission and leading as a 21st century company.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb’s Legal Department is a global team that will require working with diverse international colleagues around the world. The successful candidate will be someone who is adaptable, collaborative and embodies Airbnb’s Core Values. Candidates will be required to approach complex legal issues with a balance for local and global perspectives, while being adaptable to cultural differences and nuances. A genuine and demonstrated interest in Airbnb and a commitment to ethics, integrity and fostering a workplace that emphasizes diversity and belonging is a must.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Difference You Will Make:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;We are in search of an Associate Legal Counsel for Japan. This role reports to the Associate General Counsel - Northeast Asia and serves as a legal partner to many other teams outside Legal. Collaboration will be a key attribute, as this role will work very closely with the other members of the legal team, both regionally and globally. This role needs to be based in &lt;strong&gt;Tokyo, Japan&lt;/strong&gt;.&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;A Typical Day: &lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Act as an effective and trusted partner to the fast-paced and high-performing Airbnb team.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Deliver clear, effective and practical legal advice to the various business functions. These include business development, public policy, marketing and communications.&amp;nbsp;&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Legal advice includes regulatory matters, consumer protection, competition, marketing, employment, privacy, dispute resolution, and law enforcement.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Be adept in making sensible legal risk assessments which consider practical solutions to mitigate legal risk whilst keeping business priorities at the forefront.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Qualification in Japan (as bengoshi) is a must.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Native-level command of Japanese (written and spoken) is a must.&lt;/li&gt;
&lt;li&gt;Business-level English (written and spoken) is essential. High scores in standardized tests (TOEIC/TOEFL) is a plus.&lt;/li&gt;
&lt;li&gt;Minimum 2-5 years post-qualification experience - In-house (including secondment from a law firm) in an MNC and/or start-up is a plus.&lt;/li&gt;
&lt;li&gt;Consistently delivers creative, thoughtful and business-oriented results that appropriately balance growth and risk.&lt;/li&gt;
&lt;li&gt;Tech-forward mindset with a proactive willingness to leverage AI tools to optimize legal productivity.&lt;/li&gt;
&lt;li&gt;Team player, highly collaborative with excellent communication and listening skills.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Proactive owner who takes initiative while navigating competing priorities in a fast-paced environment.&lt;/li&gt;
&lt;li&gt;Empathetic, caring and humble.&lt;/li&gt;
&lt;li&gt;Occasional international travel (typically once a year for a few days) may be required, with full consideration for individual circumstances and family commitments.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;', 'https://careers.airbnb.com/positions/7789554?gh_jid=7789554', 'active', now())
