-- greenhouse/airbnb: Associate Principal, Strategic Finance & Analytics
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('67957992-338c-4fbe-940d-6b8bbe025a2b', 'greenhouse', '8043588', 'airbnb', 'Associate Principal, Strategic Finance & Analytics', 'United States ', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Community You Will Join:&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;The Associate Principal, Strategic Finance &amp;amp; Analytics - Homes Supply role will be responsible for partnering with the business to drive growth of Airbnb’s homes supply. This role will work directly with senior leaders to measure the impact of business initiatives, influence investment in new areas, and ensure that we can link every business action to a financial outcome.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Difference You Will Make:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;This role acts as a critical finance and strategy leader, working cross-functionally to drive financial analysis and performance tracking across priorities. You will provide rigorous financial analysis that steers our homes supply team to make the right investments for short- and long-term growth. You will also provide day-to-day reporting that informs senior leaders on business performance.&lt;/p&gt;
&lt;p&gt;The ideal candidate will have strong financial acumen and the ability to present insights and recommendations to senior leaders in a concise form to shape key business decisions.&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;A Typical Day:&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Annual &amp;amp; Quarterly Planning: &lt;/strong&gt;Collaborate with business partners on the annual and quarterly planning process, ensuring alignment on both financial and strategic goals and performance.&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Strategic Initiatives: &lt;/strong&gt;Support strategic projects to improve financial outcomes, optimize operational efficiency, and ensure long-term growth. Ensure strategic and product initiatives ladder up to the overall business P&amp;amp;L to ensure initiatives align with business objectives.&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Insights &amp;amp; Analytics: &lt;/strong&gt;Provide actionable financial insights through detailed reporting and analytics. Partner with Data Science teams to enhance data accessibility, automation, and conduct in-depth financial investigations.&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Presentations to Stakeholders&lt;/strong&gt;: Regularly present financial reports, performance updates, and strategic recommendations to senior leadership and other key stakeholders.&lt;/li&gt;
&lt;li&gt;&lt;strong style=&quot;font-family: arial, helvetica, sans-serif;&quot;&gt;Business Trends &amp;amp; Variance Analysis: &lt;/strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif;&quot;&gt;Analyze business trends and drivers of variance, synthesizing complex data into actionable insights for senior leadership.&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong style=&quot;font-family: arial, helvetica, sans-serif;&quot;&gt;Budget Tracking &amp;amp; Approvals: &lt;/strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif;&quot;&gt;Own tracking and approval of requests of the team’s budget, ensuring accuracy, compliance, and alignment with organizational priorities. Proactively monitor expenditures and coordinate with relevant stakeholders to ensure requests are properly documented and justified. Provide timely updates and reporting to leadership, helping maintain fiscal discipline and support strategic decision-making.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;5+ years of experience in FP&amp;amp;A and/or business strategy. A background in strategic finance, investment banking, management consulting, and business operations is preferred.&lt;/li&gt;
&lt;li&gt;B.A. or B.S. in Finance, Accounting, Business, Mathematics or a related field (MBA or CPA is a plus).&lt;/li&gt;
&lt;li&gt;Proven experience in P&amp;amp;L management, revenue forecasting, and financial modeling. Proficiency and self-sufficiency&amp;nbsp; in spreadsheets and financial reporting tools.&lt;/li&gt;
&lt;li&gt;Proven ability to use AI to enhance processes in both quality and productivity.&lt;/li&gt;
&lt;li&gt;Strong strategic and critical thinking skills with the ability to synthesize financial data and make recommendations that drive business outcomes.&lt;/li&gt;
&lt;li&gt;Excellent written and verbal communication skills with the ability to present complex financial data to non-financial stakeholders and senior leadership.&lt;/li&gt;
&lt;li&gt;Strong leadership abilities and the capacity to influence decision-making across the organization.&lt;/li&gt;
&lt;li&gt;Proactive and comfortable working in a fast-paced, collaborative, and innovative environment, with the ability to lead cross-functional teams.&lt;/li&gt;
&lt;li&gt;A successful candidate will model our core values, demonstrating sound judgment and thoughtfulness in all decision-making.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;color: #000000; font-family: arial, helvetica, sans-serif;&quot;&gt;&lt;strong&gt;Your Location:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;This position is US - Remote Eligible. The role may include occasional work at an Airbnb office or attendance at offsites, as agreed to with your manager. While the position is Remote Eligible, you must live in a state where Airbnb, Inc. has a registered entity. &lt;a style=&quot;color: #000000;&quot; href=&quot;https://careers.airbnb.com/&quot;&gt;Click here for the up-to-date list of excluded states. This list is continuously evolving, so please check back with us if the state you live in is on the exclusion list&lt;/a&gt; &lt;/span&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;&amp;nbsp;If your position is employed by another Airbnb entity, your recruiter will inform you what states you are eligible to work from.&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-weight: 400; font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: &lt;/span&gt;&lt;a style=&quot;color: #000000;&quot; href=&quot;mailto:reasonableaccommodations@airbnb.com&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;reasonableaccommodations@airbnb.com&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process.&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-weight: 400; font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application.&lt;/span&gt;&lt;/p&gt;&lt;div class=&quot;content-pay-transparency&quot;&gt;&lt;div class=&quot;pay-input&quot;&gt;&lt;div class=&quot;description&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0);&quot;&gt;How We&#39;ll Take Care of You:&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p class=&quot;p1&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;Our job titles may span more than one career level. The actual base pay is dependent upon many factors, such as: training, transferable skills, work experience, business needs and market demands. The base pay range is subject to change and may be modified in the future. This role may also be eligible for bonus, equity, benefits, and Employee Travel Credits. &amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;div class=&quot;title&quot;&gt;Pay Range&lt;/div&gt;&lt;div class=&quot;pay-range&quot;&gt;&lt;span&gt;$157,000&lt;/span&gt;&lt;span class=&quot;divider&quot;&gt;&amp;mdash;&lt;/span&gt;&lt;span&gt;$172,000 USD&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', 'https://careers.airbnb.com/positions/8043588?gh_jid=8043588', 'active', now())
