-- greenhouse/airbnb: Brand Media Lead
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('61b93b59-0100-4f8a-82e5-447d74cb9d0d', 'greenhouse', '8052721', 'airbnb', 'Brand Media Lead', 'United States', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;strong&gt;The Community You Will Join:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;You will be joining a team at Airbnb that is driven through collaboration; filled with brilliant and experienced minds across product, brand, design, creative, and performance.&amp;nbsp; The beauty of this role is that the media discipline serves as a facilitator of cross-functional integration. It’s entrepreneurial, fast paced, and for the right person the right mix of exhilarating and challenging.&lt;/p&gt;
&lt;p&gt;As the Media Lead for North America (US &amp;amp; CA), you will manage our regional relationships with our global media agencies of record and work with the marketing and cross-functional teams based throughout the region to ensure cohesive regional media strategies focused around internally-aligned go-to-market approaches. This role requires close collaboration with teams across Airbnb, including Regional Brand Marketing, Growth Marketing, Measurement &amp;amp; Analytics, Consumer Insights, FP&amp;amp;A (Financial Planning and Analysis), Data Science, Social and Corporate Communications teams.&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;The Difference You Will Make:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;In this pivotal role, you’ll shape and execute global campaigns by creating locally relevant strategies that truly connect with regional audiences. You will optimize for media efficiency, creative execution, local relevance and campaign objectives. You will drive global influence and connectivity through US work, while maintaining local connection with Canadian and US marketplace and consumers to inform regionally driven initiatives and excellence.&amp;nbsp;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Success in this role looks like autonomy and influence over the majority of our global efforts.&amp;nbsp; They will be a subject matter expert in brand paid media, but will communicate through the lens of storytelling and integrated strategy.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Strong but attentive partnership with media agency&lt;/li&gt;
&lt;li&gt;Create trusted internal relationships to facilitate strategy and tactics within our in-house approach.&lt;/li&gt;
&lt;li&gt;Identify tactical, process, and resource opportunities to better position brand approach.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;A Typical Day:&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;You will plan and oversee all media strategies and spend including digital, video, social, podcasts, ooh, cinema, and direct marketing initiatives. Lead media strategies to drive brand behaviors through all platforms with emphasis in leading integrated and social innovation in the areas of storytelling, branding, marketing, product, and partnerships.&lt;/li&gt;
&lt;li&gt;Drive global influence and connectivity through US work while maintaining local connection with Canadian (english + french) and US marketplace and consumers to inform regionally driven initiatives and excellence.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Lead development of global campaigns from connections strategy through campaign execution and reporting. Areas of focus include connections planning, media mix development, media planning &amp;amp; buying, performance measurement, budget management, online tracking, buy evaluation, and optimization.&lt;/li&gt;
&lt;li&gt;Integrate efforts across cross-functional stakeholders; including global marketing, local business needs, resourcing, and media partners.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Support budget and strategy planning with global teams, working closely with Financial Planning (FP&amp;amp;A) and Marketing Leadership.&lt;/li&gt;
&lt;li&gt;Partner with a global media team, based in EMEA and APAC, to develop truly nuanced and culturally relevant media strategies worldwide.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Passion for all things Airbnb. Experience hosting on the site is a huge plus.&lt;/li&gt;
&lt;li&gt;12+ years experience at digital, advertising or media agencies and/or experience managing media at a client business — preferably in the consumer internet space in travel, design, technology, or lifestyle brands.&lt;/li&gt;
&lt;li&gt;Ability to lead plan development from beginning to end with little oversight. You’ll demonstrate your ability to think holistically but also ensure the details are addressed.&lt;/li&gt;
&lt;li&gt;Agile and able to adapt quickly when working in-high growth business.&lt;/li&gt;
&lt;li&gt;In-depth knowledge of the efficacy of all media channels, with a proven track record in digital, social, and offline media. Deep understanding of market trends and fluency with brand measurement metrics and analytics.&lt;/li&gt;
&lt;li&gt;Experience in managing Global media programs and evaluating strategic, local media partners.&lt;/li&gt;
&lt;li&gt;Digital expertise with strong social platform competencies and ability to drive aggressive growth and testing frameworks.&lt;/li&gt;
&lt;li&gt;Experience in building new media and non-traditional partnerships to create tangible product extensions and integrated campaign work to lift awareness and adoption.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;color: #000000; font-family: arial, helvetica, sans-serif;&quot;&gt;&lt;strong&gt;Your Location:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;This position is US - Remote Eligible. The role may include occasional work at an Airbnb office or attendance at offsites, as agreed to with your manager. While the position is Remote Eligible, you must live in a state where Airbnb, Inc. has a registered entity. &lt;a style=&quot;color: #000000;&quot; href=&quot;https://careers.airbnb.com/&quot;&gt;Click here for the up-to-date list of excluded states. This list is continuously evolving, so please check back with us if the state you live in is on the exclusion list.&lt;/a&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt; If your position is employed by another Airbnb entity, your recruiter will inform you what states you are eligible to work from.&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-weight: 400; font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: &lt;/span&gt;&lt;a style=&quot;color: #000000;&quot; href=&quot;mailto:reasonableaccommodations@airbnb.com&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;reasonableaccommodations@airbnb.com&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process.&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-weight: 400; font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application.&lt;/span&gt;&lt;/p&gt;&lt;div class=&quot;content-pay-transparency&quot;&gt;&lt;div class=&quot;pay-input&quot;&gt;&lt;div class=&quot;description&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0);&quot;&gt;How We&#39;ll Take Care of You:&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p class=&quot;p1&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;Our job titles may span more than one career level. The actual base pay is dependent upon many factors, such as: training, transferable skills, work experience, business needs and market demands. The base pay range is subject to change and may be modified in the future. This role may also be eligible for bonus, equity, benefits, and Employee Travel Credits. &amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;div class=&quot;title&quot;&gt;Pay Range&lt;/div&gt;&lt;div class=&quot;pay-range&quot;&gt;&lt;span&gt;$160,000&lt;/span&gt;&lt;span class=&quot;divider&quot;&gt;&amp;mdash;&lt;/span&gt;&lt;span&gt;$200,000 USD&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', 'https://careers.airbnb.com/positions/8052721?gh_jid=8052721', 'active', now())
