-- greenhouse/airbnb: Business Operations and Growth Lead
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('8715a4b9-042c-410e-b533-de7e3ce9407e', 'greenhouse', '7999656', 'airbnb', 'Business Operations and Growth Lead', 'Sydney, Australia', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Community You Will Join:&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;Every day, Airbnb hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way. Since our founding, more than 5 million hosts have welcomed over 1.5 billion guest arrivals in almost every country across the globe.&amp;nbsp;&lt;/p&gt;
&lt;p&gt;The Chief Business Officer organization plays a pivotal role in driving the company’s growth and expansion efforts worldwide. Our teammates work on commercializing Airbnb’s new and existing businesses, helping Airbnb expand beyond its core offering as a place to stay. This includes recruiting and developing Airbnb’s global supply of high-quality stays, and executing Airbnb’s global strategy in the market. With a focus on business strategy, quality supply and international expansion, the team is leading the way for Airbnb’s continued growth and success in its next chapter.&amp;nbsp;&lt;/p&gt;
&lt;p&gt;The Global Markets Team, which sits within CBO, ensures that Airbnb is locally relevant and serves the needs of our global hosts and guests, helping regions more efficiently plan and execute growth strategies across supply, demand, and other surfaces in a way that will resonate with our communities.&amp;nbsp;&lt;/p&gt;
&lt;p&gt;As we expand our business, we look for the best and brightest to drive strategic business decisions. To this end, the team is looking for a Business Operations and Growth Lead to join our Australia and New Zealand team (ANZ).&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;The Difference You Will Make:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;You will work closely with the cross-functional leaders and teams, and play a key role in scaling our community growth and optimization-focused programs. The successful candidate will report to the Country Manager, ANZ.&amp;nbsp;This role is based in Sydney and will require in-person office attendance, with flexibility on the days and frequency.&lt;/p&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;A Typical Day: &lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&amp;nbsp;Align all functions&amp;nbsp; to achieve Australia and New Zealand’s business objectives in partnership with the Country Manager.&lt;/li&gt;
&lt;li&gt;Drive regular business operation meetings and initiate meaningful conversations - leading weekly meetings with cross-functional project teams to ensure key initiatives are on track in the country.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Use all available data sources and tools, internal and external, to analyze macro and micro trends, and present analysis, insights, and actionable plans to Airbnb country and regional leadership team to drive key business decisions.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Own the day-to-day business analysis.&amp;nbsp; Anticipate changes before they happen and align adjustments to&amp;nbsp; maximize growth and minimize risk.&lt;/li&gt;
&lt;li&gt;Own the conception, execution, and measurement of cross-functional initiatives end-to-end. Concretely, this means defining a crisp problem statement, articulating the ideal solution to that problem, identifying key dependencies blocking that solution, and then working with cross-functional stakeholders to achieve the solution. These initiatives will span across the demand, supply, and regulatory surfaces of the business.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Assist the country Manager in owning the performance narrative for key metrics and deliver the story to senior leaders in a concise and clear manner in weekly, monthly, and quarterly business reviews&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Minimum of 10+ years of work experience, preferably with combined exposure to business growth, business analytics, and project management in a dynamic entrepreneurial environment.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;A proven bias to action and ability to own a project from conception through to post-mortem.&lt;/li&gt;
&lt;li&gt;Ability to work in a world of uncertainty and ambiguity - to create clarity from abstraction.&lt;/li&gt;
&lt;li&gt;A familiarity with AI tools would be considered an asset.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;A world class written and verbal communicator with the ability to present at all levels of an organization in a succinct, clear and eloquent manner.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;A proven track record of being able to storytell, influence and rally diverse cross-functional stakeholders against a common mission or goal using both qualitative and quantitative insights.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Ability to not only dive into details to drive execution but also zoom out to contextualize specific recommendations/initiatives within the broader company strategy.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Ability to multi-task by prioritizing work and coordinating required support across various functions to achieve project goals and objectives.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Impeccable organizational skills, attention to detail and ability to document processes &amp;amp; decisions made.&lt;/li&gt;
&lt;li&gt;Experience implementing and scaling initiatives across globally dispersed teams.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Experience working cross-functionally with multiple departments.&lt;/li&gt;
&lt;li&gt;Hands-on approach, getting things done fast.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Comfort with manipulating large datasets in excel is a must. SQL proficiency strongly preferred.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;', 'https://careers.airbnb.com/positions/7999656?gh_jid=7999656', 'active', now())
