-- greenhouse/airbnb: Community Engagement Lead, Spain and Portugal
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('3b3db9d6-dea3-40ce-9f3b-ee88c82438bf', 'greenhouse', '7982715', 'airbnb', 'Community Engagement Lead, Spain and Portugal', 'Barcelona, Spain', NULL, NULL, '&lt;div class=&quot;content-intro&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 12pt;&quot;&gt;Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;p&gt;&lt;strong&gt;The Community You Will Join:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;Every day, millions of Airbnb hosts around the world create comfortable, reliable and welcoming stays and Experiences for our guests. Hosting on Airbnb offers a unique way to meet our Hosts’ financial goals but the rewards for opening their home or sharing a passion go beyond their bank account. Hosting also offers the opportunity to impact their local community, share their culture and connect with people they wouldn’t have met otherwise.&lt;br&gt;&lt;br&gt;We know that our global community of hosts is one of Airbnb’s most precious assets and we are very intentional on how we nurture the common identity of being an Airbnb Host. The Airbnb Community team is looking for an experienced Community Engagement Lead to work in the territory and deliver upon our Community Growth, Engagement and business goals.&amp;nbsp;&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;The Difference You will Make:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;The Airbnb team is looking for a Community Engagement Lead to build and lead our Host Community strategy in Spain and Portugal. You will regionally implement and iterate on Community programs that engage Hosts at scale, such as the Host Clubs program and Host events, while also innovating and testing new methods that can influence and strengthen the global community strategy.&lt;/p&gt;
&lt;p&gt;In this role, Community custodians in each region are responsible for balancing the needs of our Hosting Community with those of Airbnb. You will work closely with and report to the Community Regional Lead and build collaborative relationships with the relevant Country Manager, Policy, Legal, Marketing and Communications Leads, supply teams and central Community team to support our hosts.&amp;nbsp;&lt;/p&gt;
&lt;p&gt;The ideal candidate has extensive Community experience and knowledge, especially in developing Community strategies as well as building and maintaining programs that connect and engage at scale.&amp;nbsp;&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;A Typical Day:&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;Overall:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Act as the primary bridge between the local Airbnb team and the Host Community, coordinating and prioritizing cross functional activities that entail community action across the territory&lt;/li&gt;
&lt;li&gt;Lead Community growth, engagement and impact projects and initiatives from planning to delivery. This includes developing project plans, collaborating with cross-functional teams, coordinating multiple stakeholders, identifying project risks and crafting mitigation plans.&lt;/li&gt;
&lt;li&gt;Develop and execute local Community Programs with clear communication, efficient resource usage, and a deep focus on overall project execution.&lt;/li&gt;
&lt;li&gt;Collaborate across functions to drive meaningful impact within Airbnb and its Host Community, working closely with Country Manager, the policy, legal, communications, marketing, partnerships, and supply teams.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Coordinate the activities and daily operations of one Community Engagement Manager.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Community Growth:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Develop and test new value propositions and methods for growing our host communities across Spain and Portugal.&lt;/li&gt;
&lt;li&gt;Identify new approaches to recruit, onboard and manage new community leaders&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Community Engagement:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Design effective initiatives for our train the trainer model, and content strategies to drive Host engagement in Community programs and foster conversation&lt;/li&gt;
&lt;li&gt;Support global Community Engagement Programming and evolve for local language and needs&lt;/li&gt;
&lt;li&gt;Lead and organise effective Community events, both online and in-person&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Community Impact:&amp;nbsp;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Identify country needs and develop&amp;nbsp; in-market projects to drive Host success and accelerate business goals.&lt;/li&gt;
&lt;li&gt;Develop resources, engaging and high impact communications, and training materials for cross functional business partners.&lt;/li&gt;
&lt;li&gt;Work with relevant regional stakeholders to help them leverage and collaborate with the Host Community and help them identify and test new opportunities to do so.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Influence regional prioritization, process improvement, and program feedback.&lt;/li&gt;
&lt;li&gt;Develop deep knowledge of your assigned geographic markets and become the go-to source for all Host Community information relating to local needs, trends and market dynamics for internal and external partners.&lt;/li&gt;
&lt;li&gt;Co-develop strategies in partnership with Supply teams to optimize host performance across quality, pricing, and availability, empowering hosts with the tools and insights needed to set them up for long-term success.&lt;/li&gt;
&lt;li&gt;Leverage familiarity with STR regulatory environments to drive host engagement and education on compliance initiatives and regulatory obligations collaborating closely with Policy and Legal teams to ensure hosts are informed and well-supported.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;Your Expertise:&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;10+ years of experience in Community Management, Strategy, Innovation, Operations, Project Management&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Strong strategic project management skills with experience leading programs and processes.&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Ability to approach Community through a strategic business lens and align Community goals with business goals&lt;/li&gt;
&lt;li&gt;Familiar with regulatory environments&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Entrepreneurial, solution oriented, growth mindset&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Highly autonomous and self-driven&amp;nbsp;&lt;/li&gt;
&lt;li&gt;Strong verbal communication and interpersonal skills&lt;/li&gt;
&lt;li&gt;Effective cross functional partner with ability to influence through persuasion, negotiation, and consensus building&lt;/li&gt;
&lt;li&gt;Passion for Airbnb, our Hosts, and the mission of the company - being an Airbnb host is a plus&lt;/li&gt;
&lt;li&gt;Spanish mother tongue and fluent English. Ideally also fluent in Portuguese.&lt;/li&gt;
&lt;li&gt;Excellent written and oral communication skills&lt;/li&gt;
&lt;li&gt;Based in Barcelona&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;&lt;strong&gt;Our Commitment To Inclusion &amp;amp; Belonging:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: #000000;&quot;&gt;Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.&lt;/span&gt;&lt;/p&gt;&lt;div class=&quot;content-pay-transparency&quot;&gt;&lt;div class=&quot;pay-input&quot;&gt;&lt;div class=&quot;description&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0);&quot;&gt;How We&#39;ll Take Care of You:&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;Our job titles may span more than one career level. The actual base pay is dependent upon many factors, such as: training, transferable skills, work experience, business needs and market demands. The base pay range shown below is annualized, is subject to change and may be modified in the future. This role may also be eligible for bonus, equity, benefits, and Employee Travel Credits.&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;div class=&quot;title&quot;&gt;Spain Annual Pay Range&lt;/div&gt;&lt;div class=&quot;pay-range&quot;&gt;&lt;span&gt;€80.000&lt;/span&gt;&lt;span class=&quot;divider&quot;&gt;&amp;mdash;&lt;/span&gt;&lt;span&gt;€100.000 EUR&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', 'https://careers.airbnb.com/positions/7982715?gh_jid=7982715', 'active', now())
