-- greenhouse/stripe: Account Executive, Billing
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('6d0228d8-bcb9-4be7-b197-53273ed7b092', 'greenhouse', '8029128', 'stripe', 'Account Executive, Billing', 'Sydney', NULL, NULL, '&lt;h2&gt;&lt;strong&gt;Who we are&lt;/strong&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;strong&gt;About Stripe&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;Stripe is a financial infrastructure platform for businesses. Millions of companies from the world&#39;s largest enterprises to the most ambitious startups use Stripe to accept payments, grow their revenue, and accelerate new business opportunities. Our mission is to increase the GDP of the internet, and we have a staggering amount of work ahead. That means you have an unprecedented opportunity to put the global economy within everyone&#39;s reach while doing the most important work of your career.&lt;/p&gt;
&lt;h3&gt;&lt;strong&gt;About the team&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;Product Sales is a team of functional and technical specialists who both lead and advise on deals for the most strategically important products in Stripe’s portfolio. Revenue suite Product Sales is tasked with attacking a $100B market opportunity for back office finance automation across billing, tax, revenue reporting, and data.&lt;/p&gt;
&lt;h2&gt;&lt;strong&gt;What you’ll do&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;As a Billing Account Executive at Stripe, you&#39;ll use your sales and product expertise to help drive growth through existing Stripe customers. You&#39;ll collaborate with the core sales, marketing, product marketing, and product teams to develop deep product and industry knowledge and drive strategic deals. You&#39;ll lead in-depth product discussions with existing and prospective customers and build and execute against our go-to-market strategy.&lt;/p&gt;
&lt;h3&gt;&lt;strong&gt;Responsibilities&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Drive revenue to achieve targets&lt;/li&gt;
&lt;li&gt;Lead sales and upsell conversations of Stripe for existing and prospective customers&lt;/li&gt;
&lt;li&gt;Drive strategic thought leadership within assigned territory to ensure user success and revenue growth&lt;/li&gt;
&lt;li&gt;Understand the sales process and competitors for Stripe, including software, hardware, and payments&lt;/li&gt;
&lt;li&gt;Serve as both an internal and customer-facing expert on Stripe, especially for your specialised products&lt;/li&gt;
&lt;li&gt;Synthesize and relay customer feedback and our findings to inform Stripe&#39;s product roadmap&lt;/li&gt;
&lt;li&gt;Engage with Product, Marketing, and User Operations teams to help amplify our growth trajectory&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;strong&gt;Who you are&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;&lt;em&gt;&lt;br&gt;&lt;/em&gt;You&#39;re an adept salesperson, capable of engaging in business-level and technical conversations at multiple levels of the organization, including CEO, CFO, and CTO. You&#39;re used to building value in competitive situations and enjoy working on products that require deep product understanding, combined with technical knowledge. You&#39;re as comfortable working with clients as with internal stakeholders (including executives). You&#39;re excited to become an expert and to share your knowledge. You&#39;re an organized self-starter, an excellent communicator who is detail-oriented and has a track record for improving the processes and organizations around you.&lt;/p&gt;
&lt;h3&gt;&lt;strong&gt;Minimum requirements&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;8+ years of sales or prospecting experience at a technology company and a track record of top performance&lt;/li&gt;
&lt;li&gt;Owning a direct sales quota, with direct sales experience closing new business and expanding existing users&lt;/li&gt;
&lt;li&gt;A proven ability to build strong collaborative working relationships with business partners&lt;/li&gt;
&lt;li&gt;The ability to deal with ambiguity and thrive in an unstructured, fast-moving environment&lt;/li&gt;
&lt;li&gt;A proven ability to be a self-starter capable of driving business results without significant supervision&lt;/li&gt;
&lt;li&gt;A hands-on mentality&lt;/li&gt;
&lt;li&gt;Excellent verbal and written communication skills&lt;/li&gt;
&lt;li&gt;Strong presentation skills, particularly for in-person meetings with multiple stakeholders&lt;/li&gt;
&lt;li&gt;Proven ability to lead complex negotiations involving bespoke commercial agreements&lt;/li&gt;
&lt;li&gt;Ability to understand complex technical requirements and craft solutions across multiple stakeholders&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;strong&gt;Preferred qualifications&lt;/strong&gt;&amp;nbsp;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;ul&gt;
&lt;li&gt;5+ years of experience selling financial services or similar software&lt;/li&gt;
&lt;li&gt;Experience in selling billing solutions&lt;/li&gt;
&lt;li&gt;Proven ability to sell in a fast-paced environment&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;', 'https://stripe.com/jobs/search?gh_jid=8029128', 'active', now())
