-- greenhouse/stripe: Account Executive, Enterprise Grower (Australia)
INSERT INTO postings (id, source, external_id, company, title, location, employment_type, remote, raw_description, source_url, status, last_seen_at)
VALUES ('0c61a2bc-596e-4f39-805a-c06b4ac7645e', 'greenhouse', '7717676', 'stripe', 'Account Executive, Enterprise Grower (Australia)', 'Sydney, Australia', NULL, NULL, '&lt;h2&gt;Who we are&lt;/h2&gt;
&lt;h3&gt;About Stripe&lt;/h3&gt;
&lt;p&gt;Stripe is a financial infrastructure platform for businesses. Millions of companies—from the world&#39;s largest enterprises to the most ambitious startups—use Stripe to accept payments, grow their revenue, and accelerate new business opportunities. Our mission is to increase the GDP of the internet, and we have a staggering amount of work ahead. That means you have an unprecedented opportunity to put the global economy within everyone&#39;s reach while doing the most important work of your career.&lt;/p&gt;
&lt;h3&gt;About the team&lt;/h3&gt;
&lt;p&gt;As an Account Executive on the Enterprise team at Stripe, you&#39;ll drive future growth at Stripe by building new relationships with prospective companies, turning them into happy Stripe users. You&#39;ll manage and elevate relationships with a named account list within a key vertical while identifying new growth opportunities and ways Stripe can exceed expectations. This role will be dedicated to accounts focused in Australia.&lt;/p&gt;
&lt;h2&gt;What you&#39;ll do&lt;/h2&gt;
&lt;p&gt;As an Enterprise Account Executive, you&#39;ll own the full sales cycle, from prospecting and closing to managing existing relationships and identifying new opportunities to expand the Stripe footprint within existing accounts. Specifically, we&#39;re looking for someone who can execute on long-term sales strategies, engage with internal and external stakeholders, align on technical and business requirements with product teams, build value in competitive situations, lead commercial negotiations, and close deals.&lt;/p&gt;
&lt;p&gt;You&#39;re a results-driven salesperson who confidently sells business value and navigates technical conversations at all levels—CTO, COO, CFO, and beyond. You&#39;ve worked with upper-middle-market or enterprise customers and understand the buyer journey. You lead complex, multi-stakeholder deals, and quickly learn products that require technical depth. Detail-oriented and outcomes-focused, you enjoy modeling business outcomes and helping customers quantify investment decisions. You love prospecting, can own the full sales cycle independently, and will help shape our sales strategy by refining messaging and building key assets. If you&#39;re motivated, resourceful, persistent, and a great teammate, we&#39;d love to talk.&lt;/p&gt;
&lt;h3&gt;Responsibilities&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Own a named account list and develop account plans for winning business with large digital-native and enterprise companies&lt;/li&gt;
&lt;li&gt;Develop outbound strategies to create and nurture opportunities&lt;/li&gt;
&lt;li&gt;Own the full sales cycle from prospecting to close, to go live&lt;/li&gt;
&lt;li&gt;Own and lead commercial negotiations to increase and retain customer revenue and Stripe market share&lt;/li&gt;
&lt;li&gt;Develop relationships with executive stakeholders at prospective users&lt;/li&gt;
&lt;li&gt;Work with company leaders from multiple functions (e.g., Engineering, Product, and Finance) to lead complex product workshops and develop financial analyses&lt;/li&gt;
&lt;li&gt;Lead and contribute to team projects to develop and refine our sales process&lt;/li&gt;
&lt;li&gt;Engage with cross-functional teams (Partners, Post-Sales, Product, and Engineering) to help drive and iterate the Stripe strategy&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;Who you are&lt;/h2&gt;
&lt;p&gt;We&#39;re looking for someone who meets the minimum requirements to be considered for the role. If you meet these requirements, you are encouraged to apply. The preferred qualifications are a bonus, not a requirement.&lt;/p&gt;
&lt;h3&gt;Minimum requirements&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;8+ years of sales experience, preferably at a technology company, with a track record of top performance&lt;/li&gt;
&lt;li&gt;Used to driving high activity with a goal of building and executing a healthy pipeline of qualified deals to close&lt;/li&gt;
&lt;li&gt;Ability to understand complex business problems companies face today, and craft solutions across multiple products&lt;/li&gt;
&lt;li&gt;Ability to develop and execute account plans spanning multiple business units across complex organizations&lt;/li&gt;
&lt;li&gt;Strong presentation skills, particularly for in-person meetings with multiple stakeholders&lt;/li&gt;
&lt;li&gt;Proven ability to lead complex negotiations involving bespoke commercial agreements&lt;/li&gt;
&lt;li&gt;Excellent verbal and written communication skills&lt;/li&gt;
&lt;li&gt;Ability to operate in a highly ambiguous and fast-paced environment&lt;/li&gt;
&lt;li&gt;Strong interest in technology&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;Preferred qualifications&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Prior experience at a growth-stage internet or software company&lt;/li&gt;
&lt;li&gt;Experience in fintech or payments is a plus&lt;/li&gt;
&lt;/ul&gt;', 'https://stripe.com/jobs/search?gh_jid=7717676', 'active', now())
