&lt;p&gt;In office locations include: San Francisco, Seattle, Chicago, New York&amp;nbsp;&lt;/p&gt;', 'https://stripe.com/jobs/search?gh_jid=7997146', 'active', now())
ON CONFLICT (source, external_id) DO UPDATE SET
  title = EXCLUDED.title,
